import React, { useState, useEffect } from 'react';
import { View, Button, Alert, Platform } from 'react-native';
import InAppPurchase from 'react-native-iap';
import DeviceInfo from 'react-native-device-info';
import { PaymentProvider } from 'some-payment-sdk'; // Replace with actual SDK

const PaymentModule = () => {
  const [products, setProducts] = useState([]);
  const [deviceIntegrity, setDeviceIntegrity] = useState(false);

  useEffect(() => {
    checkDeviceIntegrity();
    initializePaymentProvider();
    fetchProducts();
  }, []);

  const checkDeviceIntegrity = async () => {
    const isEmulator = await DeviceInfo.isEmulator();
    const isRooted = await DeviceInfo.isRooted();
    setDeviceIntegrity(!isEmulator && !isRooted);
  };

  const initializePaymentProvider = () => {
    PaymentProvider.initialize({
      apiKey: 'YOUR_API_KEY',
      environment: 'production',
    });
  };

  const fetchProducts = async () => {
    try {
      const items = await InAppPurchase.getProducts(['product1', 'product2']);
      setProducts(items);
    } catch (error) {
      console.error('Error fetching products', error);
    }
  };

  const handlePurchase = async (productId) => {
    if (!deviceIntegrity) {
      Alert.alert('Security Alert', 'Device integrity check failed.');
      return;
    }
    try {
      const purchase = await InAppPurchase.requestPurchase(productId);
      processPayment(purchase);
    } catch (error) {
      console.error('Purchase error', error);
    }
  };

  const processPayment = async (purchase) => {
    try {
      const result = await PaymentProvider.processPayment({
        transactionId: purchase.transactionId,
        amount: purchase.productId === 'product1' ? 9.99 : 19.99,
        currency: 'USD',
      });
      if (result.success) {
        Alert.alert('Payment Successful', 'Thank you for your purchase!');
      } else {
        Alert.alert('Payment Failed', 'Please try again.');
      }
    } catch (error) {
      console.error('Payment processing error', error);
    }
  };

  return (
    <View>
      {products.map((product) => (
        <Button
          key={product.productId}
          title={`Buy ${product.title}`}
          onPress={() => handlePurchase(product.productId)}
        />
      ))}
    </View>
  );
};

export default PaymentModule;